class Solution:
    def mergeTwoLists(self, list1, list2):
        vals = []
        for node in (list1, list2):
            while node:
                vals.append(node.val)
                node = node.next
        vals.sort()
        head = None
        for v in reversed(vals):
            head = ListNode(v, head)
        return head

